   295→type envBinder interface {
   296→	MustBindEnv(...string)
   297→}
   298→
   299→// bindEnvVars descends into the provided struct field binding any expected
   300→// environment variable keys it finds reflecting struct and field tags.
   301→func bindEnvVars(v envBinder, env, prefixes []string, typ reflect.Type) {
   302→	// descend through pointers
   303→	if typ.Kind() == reflect.Pointer {
   304→		typ = typ.Elem()
   305→	}
   306→
   307→	switch typ.Kind() {
   308→	case reflect.Map:
   309→		// recurse into bindEnvVars while signifying that the last
   310→		// key was unbound using the wildcard "*".
   311→		bindEnvVars(v, env, append(prefixes, wildcard), typ.Elem())
   312→
   313→		return
   314→	case reflect.Struct, reflect.Slice:
   315→		if typ.Kind() == reflect.Slice {
   316→			if typ = typ.Elem(); typ.Kind() != reflect.Struct {
   317→				break
   318→			}
   319→		}
   320→
   321→		for structField := range typ.Fields() {
   322→			key := fieldKey(structField)
   323→
   324→			bind(env, prefixes, key, func(prefixes []string) {
   325→				bindEnvVars(v, env, prefixes, structField.Type)
   326→			})
   327→		}
   328→
   329→		return
   330→	}
   331→
   332→	bind(env, prefixes, "", func(prefixes []string) {
   333→		v.MustBindEnv(strings.Join(prefixes, "."))
   334→	})
   335→}
