   410→// getFliptEnvs returns all environment variables which have FLIPT_
   411→// as a prefix. It also strips this prefix before appending them to the
   412→// resulting set.
   413→func getFliptEnvs() (envs []string) {
   414→	const prefix = "FLIPT_"
   415→	for _, e := range os.Environ() {
   416→		key, _, ok := strings.Cut(e, "=")
   417→		if ok && strings.HasPrefix(key, prefix) {
   418→			// strip FLIPT_ off env vars for convenience
   419→			envs = append(envs, key[len(prefix):])
   420→		}
   421→	}
   422→	return envs
   423→}
