   431→
   432→	if c.Authorization.Required && !c.Authentication.Required {
   433→		return errString("authorization", "requires authentication to also be required")
   434→	}
   435→
   436→	// Check that environment storage references exist in storage config
   437→	for envName, env := range c.Environments {
   438→		if env.Storage == "" {
   439→			continue
   440→		}
   441→
   442→		if _, exists := c.Storage[env.Storage]; !exists {
   443→			return errString("environments", fmt.Sprintf("%q references undefined storage %q", envName, env.Storage))
   444→		}
   445→	}
   446→
   447→	// Validate templates config
   448→	if err := c.Templates.Validate(); err != nil {
   449→		return errFieldWrap("", "templates", err)
   450→	}
   451→
   452→	return nil
   453→}
