   523→// stringToReferenceHookFunc returns a DecodeHookFunc that handles:
   524→// - ${env:VAR} - environment variables
   525→// - ${secret:key} - secret references (marked as unresolved placeholders)
   526→func stringToReferenceHookFunc() mapstructure.DecodeHookFunc {
   527→	return func(
   528→		f reflect.Type,
   529→		t reflect.Type,
   530→		data any,
   531→	) (any, error) {
   532→		if f.Kind() != reflect.String || f != reflect.TypeFor[string]() {
   533→			return data, nil
